using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ───── FormatPhoneNumber ─────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesPhonePattern()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123", DisplayName = "Too short")]
    [DataRow("12345678901", DisplayName = "Too long")]
    [DataRow("", DisplayName = "Empty")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        var ex = Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));

        Assert.AreEqual("digits", ex.ParamName);
    }

    // ───── BuildGreeting ─────

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_ReturnsGreeting()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear", result);
    }

    [TestMethod]
    public void BuildGreeting_AnyName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ContainsTitle()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");

        Assert.Contains("Dr.", result);
    }

    [TestMethod]
    [DataRow("Ms.", "Ada", "Dear Ms. Ada,")]
    [DataRow("Prof.", "Turing", "Dear Prof. Turing,")]
    public void BuildGreeting_CustomTitle_ReturnsExpected(string title, string name, string expected)
    {
        var result = _formatter.BuildGreeting(name, title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void BuildGreeting_NullName_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.BuildGreeting(null!));
    }

    [TestMethod]
    [DataRow("", DisplayName = "Empty")]
    [DataRow("   ", DisplayName = "Whitespace")]
    public void BuildGreeting_BlankName_ThrowsArgumentException(string name)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting(name));
    }

    // ───── GenerateSlug ─────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("My Post: A & B!");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_MultiWordTitle_ContainsHyphen()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingTrailingSpaces_DoesNotStartWithHyphen()
    {
        var result = _formatter.GenerateSlug("  Hello World  ");

        Assert.StartsWith("hello", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithTrailingSpecialChars_DoesNotEndWithHyphen()
    {
        var result = _formatter.GenerateSlug("Hello World!!!");

        Assert.EndsWith("world", result);
    }

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("  UPPER CASE  ", "upper-case")]
    [DataRow("special!@#chars", "special-chars")]
    [DataRow("already-slugged", "already-slugged")]
    public void GenerateSlug_VariousInputs_ReturnsExpectedSlug(string title, string expected)
    {
        Assert.AreEqual(expected, _formatter.GenerateSlug(title));
    }

    [TestMethod]
    public void GenerateSlug_NullTitle_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.GenerateSlug(null!));
    }

    [TestMethod]
    [DataRow("", DisplayName = "Empty")]
    [DataRow("   ", DisplayName = "Whitespace")]
    public void GenerateSlug_BlankTitle_ThrowsArgumentException(string title)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.GenerateSlug(title));
    }

    // ───── FormatCurrency ─────

    [TestMethod]
    public void FormatCurrency_WholeNumber_ReturnsWithTwoDecimals()
    {
        var result = _formatter.FormatCurrency(42m);

        Assert.AreEqual("$42.00", result);
    }

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_DecimalAmount_EndsWithCents()
    {
        var result = _formatter.FormatCurrency(19.50m);

        Assert.EndsWith(".50", result);
    }

    [TestMethod]
    public void FormatCurrency_Amount_MatchesCurrencyPattern()
    {
        var result = _formatter.FormatCurrency(1234.56m, "£");

        Assert.MatchesRegex(@"^£\d+\.\d{2}$", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.00m);

        Assert.Contains("-", result);
    }

    [TestMethod]
    [DataRow("$", 0.0, "$0.00")]
    [DataRow("€", 1234.5, "€1234.50")]
    [DataRow("¥", 100.0, "¥100.00")]
    public void FormatCurrency_VariousSymbolsAndAmounts_ReturnsExpected(
        string symbol, double amount, string expected)
    {
        Assert.AreEqual(expected, _formatter.FormatCurrency((decimal)amount, symbol));
    }
}

